import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Loader2, ImageIcon, Sparkles, Trash, ArrowLeft, 
  Eye, X, ShoppingBasket, Edit2, Check, Calendar, Tag
} from 'lucide-react';
import SubirImagenes from './SubirImagenes'; 

const API_URL = "http://localhost:5000"; 
const CLOUD_NAME = "dwpgncjgn";

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();

  const filaInicial = (cat = 'Almacén') => ({ 
    id: Math.random(), producto: '', precioNuevo: '', precioViejo: '', stock: '', categoria: cat, fotoSugerida: null 
  });
  
  const [filas, setFilas] = useState([filaInicial()]);
  const [publicados, setPublicados] = useState([]);
  const [galeria, setGaleria] = useState([]);
  const [fechas, setFechas] = useState({ inicio: '', fin: '' });
  const [cargando, setCargando] = useState(false);
  const [mostrarGaleria, setMostrarGaleria] = useState(false);
  const [editandoId, setEditandoId] = useState(null);
  const [formEdit, setFormEdit] = useState({});

  const cargarDatos = useCallback(async () => {
    try {
      const [resOfertas, resGaleria] = await Promise.all([
        axios.get(`${API_URL}/api/ofertas/local/${localId}`),
        axios.get(`${API_URL}/api/galeria`)
      ]);
      setPublicados(resOfertas.data || []);
      setGaleria(resGaleria.data || []);
    } catch (e) { console.error("Error al sincronizar", e); }
  }, [localId]);

  useEffect(() => { cargarDatos(); }, [cargarDatos]);

  const buscarMatch = useCallback((texto) => {
    if (!texto || texto.length < 3) return null;
    const norm = (t) => t.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^a-z0-9]/g, '');
    const textoLimpio = norm(texto);
    return galeria.find(f => {
      const refLimpia = norm(f.nombreReferencia.split('.')[0]); 
      return refLimpia.includes(textoLimpio) || textoLimpio.includes(refLimpia);
    });
  }, [galeria]);

  const handleInputChange = (id, campo, valor) => {
    setFilas(filas.map(f => {
      if (f.id === id) {
        const act = { ...f, [campo]: valor };
        if (campo === 'producto') {
          const m = buscarMatch(valor);
          act.fotoSugerida = m ? m.publicId : null;
        }
        return act;
      }
      return f;
    }));
  };

  const handlePaste = (e) => {
    e.preventDefault();
    const data = e.clipboardData.getData('Text');
    const lineas = data.split(/\r?\n/).filter(l => l.trim() !== '');
    
    const nuevas = lineas.map(line => {
      const c = line.split('\t');
      const nombre = c[0]?.trim() || '';
      const m = buscarMatch(nombre);
      return { 
        id: Math.random(), 
        producto: nombre, 
        precioNuevo: c[1]?.replace('$', '').trim() || '', 
        precioViejo: c[2]?.replace('$', '').trim() || '', 
        stock: c[3] || 0, 
        categoria: c[4]?.trim() || 'Almacén', 
        fotoSugerida: m ? m.publicId : null 
      };
    });
    setFilas(nuevas);
  };

  const publicarTodo = async () => {
    if (!fechas.inicio || !fechas.fin) return alert("Selecciona fechas de validez.");
    const validas = filas.filter(f => f.producto && f.precioNuevo);
    if (validas.length === 0) return alert("No hay productos válidos.");

    setCargando(true);
    try {
      const productos = validas.map(f => ({
        ...f,
        publicId: f.fotoSugerida || 'placeholder_id',
        fechaInicioOferta: fechas.inicio,
        fechaFinOferta: fechas.fin,
        publicado: true
      }));
      await axios.post(`${API_URL}/api/ofertas/bulk`, { localId, productos });
      setFilas([filaInicial()]);
      cargarDatos();
      alert("¡Productos sincronizados exitosamente!");
    } catch (e) { alert("Error al publicar."); } 
    finally { setCargando(false); }
  };

  // --- LÓGICA DE AGRUPACIÓN POR SECTOR ---
  const filasPorSector = filas.reduce((acc, f) => {
    const cat = f.categoria || 'Sin Categoría';
    if (!acc[cat]) acc[cat] = [];
    acc[cat].push(f);
    return acc;
  }, {});

  const renderFoto = (pid, size = "w_150,h_150") => {
    if (!pid || pid === 'placeholder_id') return <div style={thumbPlaceholder}><ImageIcon color="#cbd5e1" size={20}/></div>;
    return (
      <div style={thumbWrap}>
        <img 
          src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/${size},c_fill,f_auto,q_auto/${pid}`} 
          style={imgStyle} 
          alt="P" 
        />
      </div>
    );
  };

  return (
    <div style={containerStyle}>
      {/* Navegación y Galería (Igual a tu original) */}
      <div style={navStyle}>
        <button onClick={() => navigate(-1)} style={btnBack}><ArrowLeft size={18}/> Volver</button>
        <div style={{ display: 'flex', gap: '12px' }}>
            <button onClick={() => setMostrarGaleria(!mostrarGaleria)} style={btnVerGaleria}>
                <Eye size={18}/> {mostrarGaleria ? "Cerrar Galería" : "Ver Biblioteca"}
            </button>
            <SubirImagenes onFinished={cargarDatos} />
        </div>
      </div>

      <header style={{ marginBottom: '30px' }}>
        <h1 style={titleStyle}><ShoppingBasket color="#e67e22" size={32}/> Gestión de Inventario</h1>
      </header>

      {/* SECCIÓN CARGA MASIVA ORGANIZADA POR SECTORES */}
      <section style={cardContainer} onPaste={handlePaste}>
        <div style={cardHeader}>
          <div style={{ color: '#e67e22', fontWeight: 'bold', display:'flex', gap:8 }}><Sparkles size={20}/> Carga por Sectores (Pega aquí)</div>
          <button onClick={() => setFilas([...filas, filaInicial()])} style={btnAddRow}><Plus size={16}/> Nueva Fila</button>
        </div>

        {Object.keys(filasPorSector).map(sector => (
          <div key={sector} style={sectorBlock}>
            <div style={sectorLabel}><Tag size={14}/> Sector: {sector}</div>
            <table style={tableStyle}>
              <thead>
                <tr style={tableHead}>
                  <th style={thStyle}>Vista</th>
                  <th style={thStyle}>Producto</th>
                  <th style={thStyle}>$ Normal</th>
                  <th style={thStyle}>$ Oferta</th>
                  <th style={thStyle}>Stock</th>
                  <th style={{width: 50}}></th>
                </tr>
              </thead>
              <tbody>
                {filasPorSector[sector].map(f => (
                  <tr key={f.id} style={trStyle}>
                    <td style={tdStyle}>{renderFoto(f.fotoSugerida)}</td>
                    <td style={tdStyle}><input style={inputTable} value={f.producto} onChange={e => handleInputChange(f.id, 'producto', e.target.value)}/></td>
                    <td style={tdStyle}><input style={inputNum} type="number" value={f.precioViejo} onChange={e => handleInputChange(f.id, 'precioViejo', e.target.value)}/></td>
                    <td style={tdStyle}><input style={inputNum} type="number" value={f.precioNuevo} onChange={e => handleInputChange(f.id, 'precioNuevo', e.target.value)}/></td>
                    <td style={tdStyle}><input style={inputNum} type="number" value={f.stock} onChange={e => handleInputChange(f.id, 'stock', e.target.value)}/></td>
                    <td style={tdStyle}><button onClick={() => setFilas(filas.filter(x => x.id !== f.id))} style={btnX}><X size={18}/></button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ))}

        <div style={cardFooter}>
          <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
            <Calendar size={18} color="#64748b"/>
            <input type="date" value={fechas.inicio} onChange={e => setFechas({...fechas, inicio: e.target.value})} style={inputDate}/>
            <span style={{color:'#94a3b8'}}>al</span>
            <input type="date" value={fechas.fin} onChange={e => setFechas({...fechas, fin: e.target.value})} style={inputDate}/>
          </div>
          <button onClick={publicarTodo} style={btnPublish} disabled={cargando}>
            {cargando ? <Loader2 className="animate-spin"/> : "SINCRONIZAR EN LA NUBE"}
          </button>
        </div>
      </section>

      {/* Aquí iría la sección de "Productos en la Nube" (Tandas) que ya tenías */}
    </div>
  );
};

// --- ESTILOS ADICIONALES PARA SECTORES ---
const sectorBlock = { padding: '15px', borderBottom: '1px solid #f1f5f9', background: '#fff' };
const sectorLabel = { background: '#f8fafc', padding: '5px 15px', borderRadius: '20px', fontSize: '0.8rem', fontWeight: 'bold', color: '#64748b', display: 'inline-flex', alignItems: 'center', gap: 8, marginBottom: 10 };

// ... (El resto de tus estilos se mantienen iguales)
const containerStyle = { padding: '30px', maxWidth: '1300px', margin: '0 auto', background: '#f8fafc', minHeight: '100vh' };
const navStyle = { display: 'flex', justifyContent: 'space-between', marginBottom: '30px' };
const btnBack = { background: 'none', border: 'none', color: '#64748b', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 'bold' };
const btnVerGaleria = { background: 'white', border: '1px solid #e2e8f0', color: '#1e293b', padding: '10px 20px', borderRadius: '12px', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '8px', cursor: 'pointer' };
const cardContainer = { background: 'white', borderRadius: '20px', border: '1px solid #e2e8f0', overflow: 'hidden', marginBottom: '40px', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.05)' };
const cardHeader = { padding: '20px', borderBottom: '1px solid #f1f5f9', display: 'flex', justifyContent: 'space-between', alignItems:'center' };
const tableStyle = { width: '100%', borderCollapse: 'collapse' };
const tableHead = { background: '#f8fafc' };
const thStyle = { padding: '15px', textAlign: 'left', color: '#64748b', fontSize: '0.75rem', textTransform:'uppercase' };
const trStyle = { borderBottom: '1px solid #f1f5f9' };
const tdStyle = { padding: '12px 15px' };
const inputTable = { width: '100%', border: 'none', outline: 'none', background: 'transparent', fontSize:'0.9rem' };
const inputNum = { width: '80px', padding: '6px', border: '1px solid #e2e8f0', borderRadius: '6px' };
const cardFooter = { padding: '20px', display: 'flex', justifyContent: 'space-between', background: '#f8fafc', alignItems:'center' };
const inputDate = { padding: '8px', borderRadius: '8px', border: '1px solid #e2e8f0', fontSize:'0.8rem' };
const btnPublish = { background: '#e67e22', color: 'white', padding: '12px 25px', borderRadius: '12px', border: 'none', cursor: 'pointer', fontWeight: 'bold', display: 'flex', gap: 8 };
const titleStyle = { color: '#1e293b', margin: 0, display: 'flex', alignItems: 'center', gap: '12px' };
const btnAddRow = { background: '#f1f5f9', border: 'none', padding: '8px 15px', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold', display:'flex', gap:5, alignItems:'center' };
const thumbWrap = { width: 50, height: 50, borderRadius: 8, overflow: 'hidden', border: '1px solid #e2e8f0' };
const imgStyle = { width: '100%', height: '100%', objectFit: 'cover' };
const thumbPlaceholder = { width: 50, height: 50, background: '#f1f5f9', borderRadius: 8, display: 'flex', alignItems: 'center', justifyContent: 'center' };
const btnX = { border:'none', background:'none', cursor:'pointer', color:'#94a3b8' };

export default GestionOfertas;
